};const ReportsView = ({ stats, hotels, allReviews, allUsers, bookings, pendingPartners }) => {
  const generatePDF = () => {
    const doc = new jsPDF();
    
    // Header
    doc.setFontSize(20);
    doc.text('System Administration Report', 14, 20);
    doc.setFontSize(12);
    doc.text(`Generated: ${new Date().toLocaleDateString()}`, 14, 30);
    
    // Platform Stats
    doc.setFontSize(14);
    doc.text('Platform Overview', 14, 42);
    doc.setFontSize(11);
    doc.text(`Total Hotels: ${stats.totalHotels}`, 14, 50);
    doc.text(`Total Rooms: ${stats.totalRooms}`, 14, 57);
    doc.text(`Total Bookings: ${stats.totalBookings}`, 14, 64);
    doc.text(`Total Revenue: ₱${stats.totalRevenue.toLocaleString()}`, 14, 71);
    doc.text(`Total Reviews: ${stats.totalReviews}`, 14, 78);
       doc.text(`Average Rating: ${stats.averageRating} stars`, 14, 85);
    doc.text(`Pending Partners: ${pendingPartners.length}`, 14, 92);
    
    // Hotels Table
    doc.setFontSize(14);
    doc.text('All Hotels', 14, 106);
    
    const hotelData = hotels.map(h => [
      h.name,
      h.location?.city || '',
      h.starRating,
      h.averageRating || h.starRating || 0,
      h.reviewCount || 0,
      h.roomCount || 0
    ]);
    
       autoTable(doc, {
      startY: 111,
      head: [['Hotel Name', 'City', 'Stars', 'Rating', 'Reviews', 'Rooms']],
      body: hotelData,
      theme: 'striped',
      headStyles: { fillColor: [6, 182, 212] }
    });
    
    // Users Table
    const finalY = doc.lastAutoTable.finalY + 10;
    doc.setFontSize(14);
    doc.text('User Accounts', 14, finalY);
    
    const userData = allUsers.map(u => [
      u.name,
      u.email,
      u.role,
      u.isApproved ? 'Active' : 'Pending'
    ]);
    
        autoTable(doc, {
      startY: finalY + 5,
      head: [['Name', 'Email', 'Role', 'Status']],
      body: userData,
      theme: 'striped',
      headStyles: { fillColor: [168, 85, 247] }
    });
    
    // Bookings Table
    const finalY2 = doc.lastAutoTable.finalY + 10;
    doc.setFontSize(14);
    doc.text('Recent Bookings', 14, finalY2);
    
    const bookingData = bookings.slice(0, 20).map(b => [
      b.hotel?.name || 'N/A',
      b.user?.name || 'Guest',
      new Date(b.checkInDate).toLocaleDateString(),
      `₱${b.totalPrice}`,
      b.status
    ]);
    
       autoTable(doc, {
      startY: finalY2 + 5,
      head: [['Hotel', 'Guest', 'Check-in', 'Price', 'Status']],
      body: bookingData,
      theme: 'striped',
      headStyles: { fillColor: [34, 197, 94] }
    });
    
    doc.save(`system-report-${new Date().toISOString().split('T')[0]}.pdf`);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">Generate System Report</h2>
        <button onClick={generatePDF} className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-xl font-bold text-white hover:shadow-lg transition-all">
          <TrendingUp className="w-5 h-5" /> Download PDF
        </button>
      </div>

      <div className="grid md:grid-cols-3 gap-4">
        <StatCard icon={Building2} label="Total Hotels" value={stats.totalHotels} color="cyan" />
        <StatCard icon={Users} label="Total Users" value={allUsers.length} color="purple" />
        <StatCard icon={DollarSign} label="Total Revenue" value={`₱${stats.totalRevenue.toLocaleString()}`} color="green" />
      </div>

      <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-6 border border-white/10">
        <h3 className="text-lg font-bold mb-4">Report Preview</h3>
        <div className="space-y-4 text-gray-400">
          <p>This system report will include:</p>
          <ul className="list-disc list-inside space-y-2 ml-4">
            <li>Platform statistics (hotels, rooms, bookings, revenue)</li>
            <li>Complete hotels directory with ratings</li>
            <li>All registered user accounts</li>
            <li>Recent bookings summary</li>
            <li>Pending partner applications count</li>
          </ul>
        </div>
      </div>
    </div>
  );
};
const SystemAdminDashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [hotels, setHotels] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(false);
  
  const [pendingPartners, setPendingPartners] = useState([]);

  useEffect(() => {
    fetchPendingPartners();
  }, []);
    const [allUsers, setAllUsers] = useState([]);
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [userForm, setUserForm] = useState({
    name: '',
    email: '',
    phone: '',
    role: 'user',
    isApproved: true
  });
 

  const fetchPendingPartners = async () => {
    try {
      const response = await api.get('/auth/pending-hotel-admins');
      if (response.data.success) {
        // Map backend format to frontend format
        const mapped = response.data.data.map(user => ({
          id: user._id,
          _id: user._id,
          name: user.name,
          email: user.email,
          phone: user.phone,
          hotelName: user.hotelName,
          hotelAddress: user.hotelAddress,
          hotelCity: user.hotelCity,
          hotelCountry: user.hotelCountry,
          appliedAt: user.createdAt
        }));
        setPendingPartners(mapped);
        localStorage.setItem('pendingPartners', JSON.stringify(mapped));
      }
    } catch (err) {
      console.error('Failed to fetch pending partners', err);
      // Fallback to localStorage
      const stored = JSON.parse(localStorage.getItem('pendingPartners')) || [];
      setPendingPartners(stored);
    }
  };
    const fetchAllUsers = async () => {
    try {
      const response = await api.get('/auth/all-users');
      if (response.data.success) {
        setAllUsers(response.data.data);
      }
    } catch (err) {
      console.error('Failed to fetch users', err);
      showAlert('Error', 'Failed to fetch users');
    }
  };
  // Modal states
  const [showHotelModal, setShowHotelModal] = useState(false);
  const [showReviewsModal, setShowReviewsModal] = useState(false);
  const [editingHotel, setEditingHotel] = useState(null);
  const [selectedHotelForReviews, setSelectedHotelForReviews] = useState(null);
  
  const [alertModal, setAlertModal] = useState({ isOpen: false, title: '', message: '', type: 'error' });

  const [hotelForm, setHotelForm] = useState({
    name: '', description: '', location: { address: '', city: '', country: '' },
    images: [''], amenities: [], starRating: 5, contact: { phone: '', email: '' }
  });

      useEffect(() => { 
    fetchData(); 
    fetchAllUsers();
  }, [activeTab]);

    // Real-time polling for pending partners, users, and reviews
  useEffect(() => {
    const interval = setInterval(() => {
      fetchPendingPartners();
      fetchAllUsers();
      fetchData(); // Re-fetches hotels which includes nested reviews
    }, 5000); // Poll every 5 seconds
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const hotelsRes = await getHotels();
      if (hotelsRes.success) setHotels(hotelsRes.data);

      const bookingsRes = await getMyBookings();
      if (bookingsRes.success) setBookings(bookingsRes.data);

      const allRoomsRes = await getAllRooms();
      if (allRoomsRes.success) setRooms(allRoomsRes.data);
    } catch (err) {
      console.error('Failed to fetch data', err);
    } finally {
      setLoading(false);
    }
  };

  const showAlert = (title, message, type = 'error') => {
    setAlertModal({ isOpen: true, title, message, type });
  };

  const closeAlert = () => setAlertModal(prev => ({ ...prev, isOpen: false }));
    const handleSignOut = async () => {
    const result = await Swal.fire({
      title: 'Sign Out?',
      text: 'Are you sure you want to sign out of your account?',
      icon: 'question',
      showCancelButton: true,
      confirmButtonColor: '#ef4444',
      cancelButtonColor: '#64748b',
      confirmButtonText: 'Yes, Sign Out',
      cancelButtonText: 'Cancel',
      background: '#0f172a',
      color: '#fff',
      customClass: {
        popup: 'rounded-2xl border border-white/10',
        confirmButton: 'rounded-xl',
        cancelButton: 'rounded-xl'
      }
    });

    if (result.isConfirmed) {
      onLogout();
    }
  };

  // AUTO-CREATE HOTEL ADMIN ACCOUNT AFTER APPROVAL
  const createHotelAdminAccount = async (partnerData) => {
    try {
      // Generate a temporary password
      const tempPassword = Math.random().toString(36).slice(-8) + Math.random().toString(36).slice(-8);
      
      const adminData = {
        name: partnerData.name,
        email: partnerData.email,
        password: tempPassword,
        role: 'hotel_admin',
        hotelId: partnerData.hotelId || null,
        phone: partnerData.phone || '',
        status: 'active'
      };

      const response = await api.post('/auth/register-hotel-admin', adminData);
      
      if (response.data.success) {
        // Send email notification with credentials
        await api.post('/notifications/send-credentials', {
          email: partnerData.email,
          name: partnerData.name,
          password: tempPassword,
          role: 'Hotel Administrator'
        });
        
        return { success: true, tempPassword };
      }
    } catch (err) {
      console.error('Failed to create hotel admin account:', err);
      return { success: false, error: err.response?.data?.error || 'Failed to create account' };
    }
  };

 const handleApprovePartner = async (partner) => {
    try {
      setLoading(true);
      
      // Approve via backend API
      const response = await api.put(`/auth/approve-hotel-admin/${partner._id || partner.id}`);
      
      if (response.data.success) {
        // Remove from pending
        const updated = pendingPartners.filter(p => p.id !== partner.id && p._id !== partner._id);
        setPendingPartners(updated);
        localStorage.setItem('pendingPartners', JSON.stringify(updated));

        Swal.fire({
          icon: 'success',
          title: 'Approved!',
          html: `Hotel admin account approved for <b>${partner.name}</b>.<br>Temporary password: <b>${response.data.data.tempPassword}</b>`,
          confirmButtonColor: '#06b6d4'
        });
      } else {
        showAlert('Error', response.data.error || 'Failed to approve partner');
      }
    } catch (err) {
      showAlert('Error', err.response?.data?.error || 'Failed to approve partner');
    } finally {
      setLoading(false);
    }
  };

  const handleRejectPartner = (id) => {
    const updated = pendingPartners.filter(p => p.id !== id);
    setPendingPartners(updated);
    localStorage.setItem('pendingPartners', JSON.stringify(updated));
    Swal.fire('Rejected', 'Application has been removed.', 'info');
  };
    // USER CRUD
  const openEditUser = (userData) => {
    setEditingUser(userData);
    setUserForm({
      name: userData.name || '',
      email: userData.email || '',
      phone: userData.phone || '',
      role: userData.role || 'user',
      isApproved: userData.isApproved !== false
    });
    setShowUserModal(true);
  };

  const resetUserForm = () => {
    setUserForm({
      name: '',
      email: '',
      phone: '',
      role: 'user',
      isApproved: true
    });
    setEditingUser(null);
  };

  const handleUpdateUser = async (e) => {
    e.preventDefault();
    try {
      setLoading(true);
      const response = await api.put(`/auth/users/${editingUser._id}`, userForm);
      if (response.data.success) {
        showAlert('Success', 'User updated successfully', 'success');
        setShowUserModal(false);
        resetUserForm();
        fetchAllUsers();
      }
    } catch (err) {
      showAlert('Error', err.response?.data?.error || 'Failed to update user');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteUser = async (userId) => {
    const result = await Swal.fire({
      title: 'Delete User?',
      text: 'This action cannot be undone!',
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#ef4444',
      cancelButtonColor: '#64748b',
      confirmButtonText: 'Yes, delete!'
    });

    if (!result.isConfirmed) return;

    try {
      setLoading(true);
      await api.delete(`/auth/users/${userId}`);
      showAlert('Success', 'User deleted successfully', 'success');
      fetchAllUsers();
    } catch (err) {
      showAlert('Error', err.response?.data?.error || 'Failed to delete user');
    } finally {
      setLoading(false);
    }
  };

  const getRoleBadge = (role) => {
    switch(role) {
      case 'system_admin': return { color: 'text-purple-400 bg-purple-500/10 border-purple-500/30', icon: Crown, label: 'System Admin' };
      case 'hotel_admin': return { color: 'text-cyan-400 bg-cyan-500/10 border-cyan-500/30', icon: Shield, label: 'Hotel Admin' };
      default: return { color: 'text-green-400 bg-green-500/10 border-green-500/30', icon: User, label: 'User' };
    }
  };

  // HOTEL CRUD
  const handleCreateHotel = async (e, localForm) => {
    e.preventDefault();
    try {
      setLoading(true);
      const response = await api.post('/hotels', localForm || hotelForm);
      if (response.data.success) {
        showAlert('Success', 'Hotel created successfully', 'success');
        setShowHotelModal(false);
        resetHotelForm();
        fetchData();
      }
    } catch (err) {
      showAlert('Error', err.response?.data?.error || 'Failed to create hotel');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateHotel = async (e, localForm) => {
    e.preventDefault();
    try {
      setLoading(true);
      const response = await api.put(`/hotels/${editingHotel._id}`, localForm || hotelForm);
      if (response.data.success) {
        showAlert('Success', 'Hotel updated successfully', 'success');
        setShowHotelModal(false);
        setEditingHotel(null);
        resetHotelForm();
        fetchData();
      }
    } catch (err) {
      showAlert('Error', err.response?.data?.error || 'Failed to update hotel');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteHotel = async (hotelId) => {
    if (!window.confirm('Are you sure you want to delete this hotel? This will also delete all its rooms.')) return;
    try {
      setLoading(true);
      await deleteHotel(hotelId);
      showAlert('Success', 'Hotel deleted successfully', 'success');
      fetchData();
    } catch (err) {
      showAlert('Error', 'Failed to delete hotel');
    } finally {
      setLoading(false);
    }
  };

  const resetHotelForm = () => {
    setHotelForm({
      name: '', description: '', location: { address: '', city: '', country: '' },
      images: [''], amenities: [], starRating: 5, contact: { phone: '', email: '' }
    });
  };

  const openEditHotel = (hotel) => {
    setEditingHotel(hotel);
    setHotelForm({
      name: hotel.name, description: hotel.description, location: hotel.location,
      images: hotel.images.length > 0 ? hotel.images : [''],
      amenities: hotel.amenities || [], starRating: hotel.starRating,
      contact: hotel.contact || { phone: '', email: '' }
    });
    setShowHotelModal(true);
  };

  const openViewReviews = (hotel) => {
    setSelectedHotelForReviews(hotel);
    setShowReviewsModal(true);
  };

  // STATS
  const stats = useMemo(() => {
    const totalRevenue = bookings.filter(b => b.status === 'confirmed').reduce((sum, b) => sum + b.totalPrice, 0);
    const totalRooms = hotels.reduce((sum, h) => sum + (h.roomCount || 0), 0);
    const totalReviews = hotels.reduce((sum, h) => sum + (h.reviewCount || 0), 0);
    const averageRating = hotels.length > 0 ? (hotels.reduce((sum, h) => sum + (h.averageRating || 0), 0) / hotels.length).toFixed(1) : 0;
    
    return {
      totalHotels: hotels.length, totalRooms, totalBookings: bookings.length,
      totalRevenue, totalReviews, averageRating,
      cancelledBookings: bookings.filter(b => b.status === 'cancelled').length,
      confirmedBookings: bookings.filter(b => b.status === 'confirmed').length
    };
  }, [hotels, bookings]);

 

  const allReviews = useMemo(() => {
    const reviews = [];
    hotels.forEach(hotel => {
      if (hotel.reviews?.length > 0) {
        hotel.reviews.forEach(review => {
          reviews.push({ ...review, hotelId: hotel._id, hotelName: hotel.name, hotelImage: hotel.images?.[0] });
        });
      }
    });
    return reviews.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  }, [hotels]);

  
  return (
    <div className="min-h-screen bg-slate-950 text-white flex">
      <AlertModal isOpen={alertModal.isOpen} onClose={closeAlert} title={alertModal.title} message={alertModal.message} type={alertModal.type} />
      <HotelModal showHotelModal={showHotelModal} setShowHotelModal={setShowHotelModal} editingHotel={editingHotel}
        hotelForm={hotelForm} setHotelForm={setHotelForm} loading={loading} handleCreateHotel={handleCreateHotel} handleUpdateHotel={handleUpdateHotel} />
      <ReviewsModal showReviewsModal={showReviewsModal} setShowReviewsModal={setShowReviewsModal} selectedHotelForReviews={selectedHotelForReviews} />
            <UserModal showUserModal={showUserModal} setShowUserModal={setShowUserModal} editingUser={editingUser}
        userForm={userForm} setUserForm={setUserForm} loading={loading} handleUpdateUser={handleUpdateUser} />
      
            <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        pendingPartners={pendingPartners} 
        allUsers={allUsers} 
        stats={stats} 
        user={user} 
        handleSignOut={handleSignOut} 
      />

      <div className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && <DashboardView stats={stats} hotels={hotels} allReviews={allReviews} />}
          {activeTab === 'hotels' && <HotelsView hotels={hotels} openViewReviews={openViewReviews} openEditHotel={openEditHotel} handleDeleteHotel={handleDeleteHotel} />}
          {activeTab === 'partners' && <PartnersView pendingPartners={pendingPartners} handleRejectPartner={handleRejectPartner} handleApprovePartner={handleApprovePartner} />}
          {activeTab === 'users' && <UsersView allUsers={allUsers} getRoleBadge={getRoleBadge} openEditUser={openEditUser} handleDeleteUser={handleDeleteUser} />}
          {activeTab === 'reviews' && <ReviewsView stats={stats} allReviews={allReviews} />}
          {activeTab === 'reports' && <ReportsView stats={stats} hotels={hotels} allReviews={allReviews} allUsers={allUsers} bookings={bookings} pendingPartners={pendingPartners} />}
        </div>
      </div>
    </div>
  );
};

export default SystemAdminDashboard;
